import Wizard from '@/components/shared/Wizard';
import { LuUser, LuFileText, LuCheckCircle } from 'react-icons/lu';

const KYCWizard = () => {
  const [currentStep, setCurrentStep] = useState(0);

  return (
    <Wizard current={currentStep} vertical onChange={setCurrentStep}>
      <Wizard.Step 
        title="Personal Information" 
        customIcon={<LuUser />}
      >
        <PersonalInfoForm onNext={() => setCurrentStep(1)} />
      </Wizard.Step>

      <Wizard.Step 
        title="Document Upload" 
        customIcon={<LuFileText />}
      >
        <DocumentUploadForm 
          onPrevious={() => setCurrentStep(0)}
          onNext={() => setCurrentStep(2)}
        />
      </Wizard.Step>

      <Wizard.Step 
        title="Verification" 
        customIcon={<LuCheckCircle />}
      >
        <VerificationStep onPrevious={() => setCurrentStep(1)} />
      </Wizard.Step>
    </Wizard>
  );
};

const [currentStep, setCurrentStep] = useState(0);
const [formData, setFormData] = useState({
  step1Complete: false,
  step2Complete: false
});

const handleStepChange = (index: number) => {
  // Validate before allowing navigation
  if (index > currentStep) {
    // Moving forward - check if current step is complete
    if (currentStep === 0 && !formData.step1Complete) {
      toast.error('Please complete step 1 first');
      return;
    }
    if (currentStep === 1 && !formData.step2Complete) {
      toast.error('Please complete step 2 first');
      return;
    }
  }
  setCurrentStep(index);
};

<Wizard current={currentStep} onChange={handleStepChange}>
  <Wizard.Step title="Step 1">
    <Step1Form 
      onComplete={() => {
        setFormData({ ...formData, step1Complete: true });
        setCurrentStep(1);
      }}
    />
  </Wizard.Step>

  <Wizard.Step 
    title="Step 2" 
    disabled={!formData.step1Complete}
  >
    <Step2Form 
      onComplete={() => {
        setFormData({ ...formData, step2Complete: true });
        setCurrentStep(2);
      }}
    />
  </Wizard.Step>

  <Wizard.Step 
    title="Complete" 
    disabled={!formData.step2Complete}
  >
    <CompletionStep />
  </Wizard.Step>
</Wizard>

import { useEffect } from 'react';

const [currentStep, setCurrentStep] = useState(() => {
  // Load saved progress from localStorage
  const saved = localStorage.getItem('wizardProgress');
  return saved ? JSON.parse(saved).currentStep : 0;
});

const [formData, setFormData] = useState(() => {
  const saved = localStorage.getItem('wizardProgress');
  return saved ? JSON.parse(saved).formData : {};
});

// Save progress whenever it changes
useEffect(() => {
  localStorage.setItem('wizardProgress', JSON.stringify({
    currentStep,
    formData
  }));
}, [currentStep, formData]);

const handleComplete = () => {
  // Clear saved progress on completion
  localStorage.removeItem('wizardProgress');
